# Module providing shape classes
class Rectangle:
    """Rectangle with width and height"""
    width: float
    height: float

    def __init__(self, width: float, height: float):
        self.width = width
        self.height = height

    def area(self) -> float:
        return self.width * self.height

    def __str__(self) -> str:
        return f"Rectangle({self.width}, {self.height}) area={self.area():.2f}"

class Circle:
    """Circle with radius"""
    radius: float

    def __init__(self, radius: float):
        self.radius = radius

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def __str__(self) -> str:
        return f"Circle(r={self.radius}) area={self.area():.2f}"

def calculate_total_area(rects: list[Rectangle], circles: list[Circle]) -> float:
    """Calculate total area of all shapes"""
    total: float = 0.0
    for r in rects:
        total += r.area()
    for c in circles:
        total += c.area()
    return total
